-- Confirm social stats
SELECT p.display_name, count(rl.id) as recipes_liked
FROM profiles p
JOIN recipe_likes rl ON rl.user_id = p.id
WHERE p.id::text LIKE 'a0000000-%'
GROUP BY p.display_name
ORDER BY p.display_name;
